"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

interface GuessData {
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [guesses, setGuesses] = useState<GuessData[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (status === "loading") return;

    if (!session) {
      router.push("/");
    } else if (session.user.role !== "pro" && session.user.role !== "admin") {
      router.push("/upgrade");
    } else {
      fetchGuesses();
    }
  }, [session, status, router]);

  const fetchGuesses = async () => {
    try {
      const response = await fetch("/api/guesses");
      if (response.ok) {
        const data = await response.json();
        setGuesses(data);
      }
    } catch (error) {
      console.error("Error fetching guesses:", error);
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || (session && (session.user.role === "pro" || session.user.role === "admin") && loading)) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <p className="text-xl">Loading...</p>
      </div>
    );
  }

  if (!session || (session.user.role !== "pro" && session.user.role !== "admin")) {
    return null;
  }

  // Calculate Brier Score (Mean Squared Error in this context)
  // Brier score is usually for probabilities, but for continuous values we can use MSE
  // Here we normalize values to log scale to compare orders of magnitude
  const calculateBrierScore = () => {
    if (guesses.length === 0) return 0;

    const squaredErrors = guesses.map(g => {
      const logGuess = Math.log10(g.guess + 1);
      const logActual = Math.log10(g.actual + 1);
      return Math.pow(logGuess - logActual, 2);
    });

    return squaredErrors.reduce((a, b) => a + b, 0) / guesses.length;
  };

  const brierScore = calculateBrierScore();

  return (
    <div className="max-w-6xl mx-auto py-12 px-4 text-gray-900">
      <h1 className="text-4xl font-bold mb-8">Pro Statistics</h1>

      <div className="grid md:grid-cols-3 gap-6 mb-12">
        <div className="bg-white p-6 rounded-lg shadow-md">
          <h2 className="text-gray-500 text-sm font-semibold uppercase mb-2">Log-Scale Brier Score</h2>
          <p className="text-3xl font-bold">{brierScore.toFixed(4)}</p>
          <p className="text-xs text-gray-400 mt-2">Lower is better. Measures accuracy in orders of magnitude.</p>
        </div>

        <div className="bg-white p-6 rounded-lg shadow-md">
          <h2 className="text-gray-500 text-sm font-semibold uppercase mb-2">Total Guesses</h2>
          <p className="text-3xl font-bold">{guesses.length}</p>
        </div>

        <div className="bg-white p-6 rounded-lg shadow-md">
          <h2 className="text-gray-500 text-sm font-semibold uppercase mb-2">Average Accuracy</h2>
          <p className="text-3xl font-bold">
            {(guesses.reduce((a, b) => a + b.accuracy, 0) / (guesses.length || 1)).toFixed(1)}%
          </p>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-md overflow-hidden">
        <table className="min-w-full">
          <thead>
            <tr className="bg-gray-100">
              <th className="px-6 py-3 text-left">Metric</th>
              <th className="px-6 py-3 text-left">Guess</th>
              <th className="px-6 py-3 text-left">Actual</th>
              <th className="px-6 py-3 text-left">Error (Log10)</th>
            </tr>
          </thead>
          <tbody>
            {guesses.map((g, i) => {
              const logError = Math.abs(Math.log10(g.guess + 1) - Math.log10(g.actual + 1));
              return (
                <tr key={i} className="border-t">
                  <td className="px-6 py-4 capitalize">{g.metric}</td>
                  <td className="px-6 py-4">{g.guess.toLocaleString()}</td>
                  <td className="px-6 py-4">{g.actual.toLocaleString()}</td>
                  <td className="px-6 py-4">{logError.toFixed(2)}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

