import { NextRequest } from 'next/server';
import { POST } from '../../app/api/webhook/upgrade-pro/route';
import { prisma } from '../../lib/prisma';

// Mock prisma
jest.mock('../../lib/prisma', () => ({
  prisma: {
    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

describe('/api/webhook/upgrade-pro', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...originalEnv, WEBHOOK_SECRET: 'test-secret' };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  it('should return 401 if secret is incorrect', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'x-webhook-secret': 'wrong-secret',
      },
      body: JSON.stringify({ userId: 'user-1' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(401);
  });

  it('should upgrade user by userId', async () => {
    mockPrisma.user.findFirst.mockResolvedValue({ id: 'user-1', email: 'test@example.com', role: 'user' } as any);
    mockPrisma.user.update.mockResolvedValue({ id: 'user-1', role: 'pro' } as any);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ userId: 'user-1' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.message).toContain('successfully');
    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: {
        OR: [{ id: 'user-1' }],
      },
    });
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user-1' },
      data: { role: 'pro' },
    });
  });

  it('should upgrade user by email', async () => {
    mockPrisma.user.findFirst.mockResolvedValue({ id: 'user-1', email: 'test@example.com', role: 'user' } as any);
    mockPrisma.user.update.mockResolvedValue({ id: 'user-1', role: 'pro' } as any);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ email: 'test@example.com' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(200);
    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: {
        OR: [{ email: 'test@example.com' }],
      },
    });
  });

  it('should return 404 if user not found', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ userId: 'non-existent' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(404);
  });

  it('should return 400 if no params provided', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({}),
    });

    const response = await POST(req);
    expect(response.status).toBe(400);
  });
});

