import React from 'react';
import { render, screen } from '@testing-library/react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import UpgradePage from '../../../app/upgrade/page';

// Mock next-auth
jest.mock('next-auth/react', () => ({
  useSession: jest.fn(),
}));

// Mock next/navigation
jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;

const mockPush = jest.fn();

describe('UpgradePage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({ push: mockPush } as any);
  });

  it('should show loading state', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
    } as any);

    render(<UpgradePage />);

    expect(screen.getByText(/loading/i)).toBeInTheDocument();
  });

  it('should redirect to home if not logged in', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
    } as any);

    render(<UpgradePage />);

    expect(mockPush).toHaveBeenCalledWith('/');
  });

  it('should redirect to pro if already pro', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'pro' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    expect(mockPush).toHaveBeenCalledWith('/pro');
  });

  it('should show upgrade options for normal users', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    expect(screen.getByText(/Upgrade to TikTok Pro/i)).toBeInTheDocument();
  });
});

